import { useTT } from "../../useTT.ts";
import { CashflowTableCell } from "./CashflowTableCell.tsx";
import {
  CashflowTableSummaryRow,
  CashflowTableSummaryRowLabel,
  useCashflowTable,
} from "./components/index.ts";

export function CashflowTableNetBalanceRow() {
  const { tt } = useTT();
  const { data } = useCashflowTable();

  return (
    <CashflowTableSummaryRow>
      <CashflowTableSummaryRowLabel>
        {tt("cashflowTable.rows.netBalance")}
      </CashflowTableSummaryRowLabel>
      {data?.periods.map((period, index) => (
        <CashflowTableCell
          key={period.id}
          value={period.netBalance}
          columnIndex={index}
          dateFrom={period.dateFrom}
          isBold
          colorMode="balance"
        />
      ))}
    </CashflowTableSummaryRow>
  );
}

import { useTT } from "../../useTT.ts";
import {
  CashflowTableSummaryRow,
  CashflowTableSummaryRowLabel,
  CashflowTableSummaryValueCell,
  useCashflowTable,
} from "./components/index.ts";

export function CashflowTableFinalBalanceRow() {
  const { tt } = useTT();
  const { data, currency } = useCashflowTable();

  return (
    <CashflowTableSummaryRow>
      <CashflowTableSummaryRowLabel>
        {tt("cashflowTable.rows.finalBalance")}
      </CashflowTableSummaryRowLabel>
      {data?.periods.map((period, index) => (
        <CashflowTableSummaryValueCell
          key={period.id}
          value={period.finalBalance?.value ?? null}
          balanceQuality={period.finalBalance?.balanceQuality ?? null}
          currency={currency}
          columnIndex={index}
          dateFrom={period.dateFrom}
          isBold={true}
          colorMode="final"
        />
      ))}
    </CashflowTableSummaryRow>
  );
}

import { IconArrowUpRight } from "@dfp/react-icons";

import { useTT } from "../../useTT.ts";
import {
  CashflowCategory,
  CashflowCategoryDataRow,
  CashflowCategoryHeader,
  CashflowCategoryHeaderIcon,
  CashflowCategoryHeaderTitle,
  CashflowCategoryRows,
  CashflowCategoryTrigger,
  CashflowTableSummaryValueCell,
  useCashflowTable,
} from "./components/index.ts";

/**
 * Income category breakdown with collapsible section.
 *
 * Structure:
 * - Income section header (with total, expandable)
 *   - Income category rows (indented)
 */
export function CashflowTableIncomeCategories() {
  const { data, categoryFilter, allCategories, currency } = useCashflowTable();
  const { tt } = useTT();

  return (
    <CashflowCategory>
      <CashflowCategoryHeader>
        <CashflowCategoryHeaderTitle>
          <CashflowCategoryHeaderIcon sx={{ color: "success.main" }}>
            <IconArrowUpRight />
          </CashflowCategoryHeaderIcon>
          {tt("cashflowTable.rows.income")}
          <CashflowCategoryTrigger categoryType="income" />
        </CashflowCategoryHeaderTitle>

        {data?.periods.map((period, index) => (
          <CashflowTableSummaryValueCell
            key={period.id}
            value={period.income}
            currency={currency}
            columnIndex={index}
            dateFrom={period.dateFrom}
            isBold
            colorMode="none"
          />
        ))}
      </CashflowCategoryHeader>

      <CashflowCategoryRows>
        {categoryFilter.income.map((category) => (
          <CashflowCategoryDataRow
            key={category}
            allCategories={allCategories}
            category={category}
            direction="IN"
          />
        ))}
      </CashflowCategoryRows>
    </CashflowCategory>
  );
}

import { IconArrowDownRight } from "@dfp/react-icons";

import { useTT } from "../../useTT.ts";
import {
  CashflowCategory,
  CashflowCategoryDataRow,
  CashflowCategoryHeader,
  CashflowCategoryHeaderIcon,
  CashflowCategoryHeaderTitle,
  CashflowCategoryRows,
  CashflowCategoryTrigger,
  CashflowTableSummaryValueCell,
  useCashflowTable,
} from "./components/index.ts";

/**
 * Costs category breakdown with collapsible section.
 *
 * Structure:
 * - Costs section header (with total, expandable)
 *   - Cost category rows (indented)
 */
export function CashflowTableCostsCategories() {
  const { data, categoryFilter, allCategories, currency } = useCashflowTable();
  const { tt } = useTT();

  return (
    <CashflowCategory>
      <CashflowCategoryHeader>
        <CashflowCategoryHeaderTitle>
          <CashflowCategoryHeaderIcon sx={{ color: "error.main" }}>
            <IconArrowDownRight />
          </CashflowCategoryHeaderIcon>
          {tt("cashflowTable.rows.costs")}
          <CashflowCategoryTrigger categoryType="costs" />
        </CashflowCategoryHeaderTitle>

        {data?.periods.map((period, index) => (
          <CashflowTableSummaryValueCell
            key={period.id}
            value={period.costs}
            currency={currency}
            columnIndex={index}
            dateFrom={period.dateFrom}
            isBold
            colorMode="none"
          />
        ))}
      </CashflowCategoryHeader>

      <CashflowCategoryRows>
        {categoryFilter.costs.map((category) => (
          <CashflowCategoryDataRow
            key={category}
            allCategories={allCategories}
            category={category}
            direction="OUT"
          />
        ))}
      </CashflowCategoryRows>
    </CashflowCategory>
  );
}

import type { TransactionDirection } from "@dfp/bw-isomorphic-enums";

import { CashflowTableCell } from "../CashflowTableCell.tsx";
import type {
  CashflowPeriod,
  CategoryOption,
  CategoryType,
} from "../types/index.ts";
import { getCategoryLabel } from "../utils/index.ts";
import {
  CashflowCategoryRow,
  CashflowCategoryRowLabel,
} from "./CashflowCategory.tsx";
import { useCashflowTable } from "./CashflowTableContext.tsx";
import { useOpenCategoryDetail } from "./categoryDetail/index.ts";

type CashflowCategoryDataRowProps = {
  allCategories: Array<CategoryOption>;
  category: CategoryType;
  direction: TransactionDirection;
};

export function CashflowCategoryDataRow({
  allCategories,
  category,
  direction,
}: CashflowCategoryDataRowProps) {
  const { data } = useCashflowTable();
  const categoryLabel = getCategoryLabel(category, allCategories);

  const openDetail = useOpenCategoryDetail({
    category,
    direction,
    categoryLabel,
  });

  const getCategoryValue = (period: CashflowPeriod) =>
    (direction === "IN" ? period.incomeCategories : period.costsCategories).get(
      category,
    ) ?? 0;

  return (
    <CashflowCategoryRow>
      <CashflowCategoryRowLabel category={category} direction={direction}>
        {categoryLabel}
      </CashflowCategoryRowLabel>

      {data?.periods.map((period, index) => (
        <CashflowTableCell
          key={period.id}
          value={getCategoryValue(period)}
          columnIndex={index}
          dateFrom={period.dateFrom}
          colorMode="none"
          onClick={() => openDetail(index)}
        />
      ))}
    </CashflowCategoryRow>
  );
}

import {
  Box,
  IconButton,
  SxProps,
  TableCell,
  TableRow,
  Theme,
  Tooltip,
} from "@mui/material";
import { type ReactNode, useCallback, useState } from "react";

import type { TransactionDirection } from "@dfp/bw-isomorphic-enums";
import { IconChevronDown } from "@dfp/react-icons";
import { createCheckedContext } from "@dfp/react-utils";

import { useTT } from "../../../useTT.ts";
import { useSelectedColumn } from "../../SelectionContext.tsx";
import { cashflowLayoutConfig } from "../../cashflow-layout.config.ts";
import type { CategoryType } from "../types/index.ts";
import { useOpenCategoryDetail } from "./categoryDetail/index.ts";

type CashflowCategoryContextValue = {
  isExpanded: boolean;
  toggleExpanded: () => void;
};

const [CashflowCategoryProvider, useCashflowCategory] =
  createCheckedContext<CashflowCategoryContextValue>("CashflowCategoryContext");

type CashflowCategoryProps = {
  children: ReactNode;
  defaultExpanded?: boolean;
};

export function CashflowCategory({
  children,
  defaultExpanded = true,
}: CashflowCategoryProps) {
