import { PickersDay } from "@mui/x-date-pickers";
import type { PickersDayProps } from "@mui/x-date-pickers/PickersDay";
import { Dayjs } from "dayjs";
import type { ComponentType } from "react";
import { useState } from "react";

import { useTimePeriodControls } from "../TimePeriodContext.tsx";
import { StaticCalendar } from "./StaticCalendar.tsx";

type WeekPickerProps = {
  onWeekChange: (date: Dayjs) => void;
};

export function WeekPicker({ onWeekChange }: WeekPickerProps) {
  const { selectedDay, maxDateRangeFrom, maxDateRangeTo } =
    useTimePeriodControls();

  const [value, setValue] = useState<Dayjs | null>(selectedDay);
  const [view, setView] = useState<"year" | "month" | "day">("day");

  return (
    <StaticCalendar
      value={value}
      view={view}
      onViewChange={setView}
      sx={{
        "& .MuiDateCalendar-root": {
          height: "100%",
          minHeight: "354px",
        },
        "& .MuiPickersSlideTransition-root": {
          minHeight: "260px",
        },
      }}
      onChange={(val) => {
        setValue(val);
        if (view === "day" && val) {
          onWeekChange(val);
        }
      }}
      minDate={maxDateRangeFrom}
      maxDate={maxDateRangeTo}
      views={["year", "month", "day"]}
      showDaysOutsideCurrentMonth
      slots={{
        day: WeekPickerDay as ComponentType<PickersDayProps<Dayjs>>,
      }}
      slotProps={{
        day: {
          selectedDay: value,
          minDate: maxDateRangeFrom,
          maxDate: maxDateRangeTo,
        } as Record<string, unknown>,
      }}
    />
  );
}

type WeekPickerDayProps = PickersDayProps<Dayjs> & {
  selectedDay: Dayjs | null;
  minDate: Dayjs;
  maxDate: Dayjs;
};

/**
 * Custom day component that highlights the entire week row when in week view
 */
export function WeekPickerDay({
  day,
  selectedDay,
  minDate,
  maxDate,
  ...other
}: WeekPickerDayProps) {
  if (!selectedDay) {
    return <PickersDay {...other} day={day} />;
  }

  const startOfWeek = selectedDay.startOf("isoWeek");
  const endOfWeek = selectedDay.endOf("isoWeek");
  const isInSelectedWeek =
    day.isSame(startOfWeek, "day") ||
    (day.isAfter(startOfWeek) && day.isBefore(endOfWeek)) ||
    day.isSame(endOfWeek, "day");

  const isStartOfWeek = day.isSame(startOfWeek, "day");
  const isEndOfWeek = day.isSame(endOfWeek, "day");

  // Disable days outside the available range
  const isOutsideRange =
    day.isBefore(minDate, "day") || day.isAfter(maxDate, "day");

  return (
    <PickersDay
      {...other}
      day={day}
      disabled={isOutsideRange}
      disableMargin
      selected={isInSelectedWeek}
      sx={{
        padding: 2.5,
        ...(isInSelectedWeek && {
          backgroundColor: "primary.main",
          color: "primary.contrastText",
          borderRadius: 0,
          "&:hover": {
            backgroundColor: "primary.dark",
          },
          "&:focus": {
            backgroundColor: "primary.main",
          },
        }),
        ...(isStartOfWeek &&
          isInSelectedWeek && {
            borderTopLeftRadius: "50%",
            borderBottomLeftRadius: "50%",
          }),
        ...(isEndOfWeek &&
          isInSelectedWeek && {
            borderTopRightRadius: "50%",
            borderBottomRightRadius: "50%",
          }),
      }}
    />
  );
}

import { Popover } from "@mui/material";
import { useCallback, useEffect, useMemo, useState } from "react";

import { useCompanyContext } from "@dfp/bw-react-user-context";
import { AppDialogCloseButton } from "@dfp/react-components";

import { CategoryDetail } from "../../../categoryDetail/index.ts";
import { useCashflowTable } from "../CashflowTableContext.tsx";
import type { CategoryDetailPanelParams } from "./categoryDetailPanel.context.ts";

type CategoryDetailPopoverProps = {
  anchorPosition: { left: number; top: number };
  onChangeColumn: (index: number) => void;
  onClose: () => void;
  open: boolean;
  params: CategoryDetailPanelParams | null;
};

export function CategoryDetailPopover({
  anchorPosition,
  onChangeColumn,
  onClose,
  open,
  params,
}: CategoryDetailPopoverProps) {
  const { bankAccountIdArray, currency, data, interval } = useCashflowTable();
  const { companyId } = useCompanyContext();

  const [currentIndex, setCurrentIndex] = useState(params?.columnIndex ?? 0);

  useEffect(() => {
    if (params) setCurrentIndex(params.columnIndex);
  }, [params]);

  const periods = data?.periods;
  const period = periods?.[currentIndex];

  const handleNavigate = useCallback(
    (newIndex: number) => {
      setCurrentIndex(newIndex);
      onChangeColumn(newIndex);
    },
    [onChangeColumn],
  );

  const paid = useMemo(() => {
    if (!period || !params) return 0;

    const categoriesMap =
      params.direction === "IN"
        ? period.incomeCategories
        : period.costsCategories;

    return categoriesMap?.get(params.category) ?? 0;
  }, [period, params]);

  return (
    <Popover
      anchorPosition={anchorPosition}
      anchorReference="anchorPosition"
      disableScrollLock
      onClose={onClose}
      open={open}
      sx={{ zIndex: (theme) => theme.zIndex.drawer }}
      slotProps={{
        paper: {
          sx: {
            borderRadius: (theme) => theme.borderRadius.md,
            maxWidth: 730,
            position: "relative",
            px: 3,
            width: 730,
          },
        },
      }}
      transformOrigin={{ horizontal: "right", vertical: "top" }}
    >
      <AppDialogCloseButton onClose={onClose} />

      {params && period && (
        <CategoryDetail
          bankAccountIdArray={bankAccountIdArray}
          categoryId={params.category}
          categoryLabel={params.categoryLabel}
          companyId={companyId}
          currency={currency}
          dateFrom={period.dateFrom}
          dateTo={period.dateTo}
          direction={params.direction}
          forecasted={0}
          interval={interval}
          key={`${params.category}-${params.direction}-${params.columnIndex}`}
          onNextPeriod={
            periods && currentIndex < periods.length - 1
              ? () => handleNavigate(currentIndex + 1)
              : undefined
          }
          onPreviousPeriod={
            currentIndex > 0
              ? () => handleNavigate(currentIndex - 1)
              : undefined
          }
          paid={paid}
        />
      )}
    </Popover>
  );
}

